let (ok1, res1) = r1;
let (ok2, res2) = r2;

// Lift next_ensures into a forall that z3 can re-instantiate at both runs,
// giving the two runs a shared syntactic anchor for trigger alignment.
assert forall|post_self_x: HostState, post_netc_x: NetClient, rx: (bool, Ghost<EventResults>)|
    HostState::next_ensures(pre_self_, pre_netc, post_self_x, post_netc_x, rx) implies {
        &&& rx.0 == post_netc_x.ok()
        &&& rx.0 ==> post_self_x.invariants(&post_netc_x.my_end_point())
        &&& rx.0 ==> HostState::next(pre_self_@, post_self_x@, rx.1@.ios)
        &&& rx.0 ==> rx.1@.event_seq() == rx.1@.ios
        &&& (rx.0 || rx.1@.sends.len() > 0)
                ==> post_netc_x.history() == pre_netc.history() + rx.1@.event_seq()
        &&& rx.1@.well_typed_events()
    }
by {
    lemma_next_ensures_decompose(pre_self_, pre_netc, post_self_x, post_netc_x, rx);
}

// Decompose the two-run ensures into the per-run facts via the helper lemma.
if HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1) {
    lemma_next_ensures_decompose(pre_self_, pre_netc, post1_self_, post1_netc, r1);
}
if HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2) {
    lemma_next_ensures_decompose(pre_self_, pre_netc, post2_self_, post2_netc, r2);
}
